sys_atf_test_step.step:
(function step(assert, $library) {
    // Test IDP Integration Sync CRUD operations
    // Create
    var gr = new GlideRecord('u_idp_integration_sync');
    gr.initialize();
    gr.u_name = 'Test Integration Sync ATF';
    gr.u_type = 'test';
    var id = gr.insert();
    assert.isTrue(id, 'Integration sync should be created');

    // Read
    gr = new GlideRecord('u_idp_integration_sync');
    gr.get(id);
    assert.equal(gr.u_name, 'Test Integration Sync ATF', 'Integration sync name should match');

    // Update
    gr.u_type = 'updated';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_idp_integration_sync');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Integration sync should be deleted');
})(step, $library);
